// Extract email data and generate case reference
const email = $input.item.json;

// Generate case reference: FOI-YYYY-NNNN
const year = new Date().getFullYear();
const randomNum = Math.floor(Math.random() * 9000) + 1000;
const caseRef = `FOI-${year}-${randomNum}`;

// Extract sender details
const from = email.from || '';
const senderEmail = from.match(/<(.+?)>/) ? from.match(/<(.+?)>/)[1] : from;
const senderName = from.replace(/<.+?>/, '').trim().replace(/"/g, '') || 'Unknown';

// Get received date
const receivedDate = new Date(email.date || new Date());
const receivedDateStr = receivedDate.toLocaleDateString('en-GB', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

// Calculate 20-working-day deadline (skip weekends, approximate for bank holidays)
function addWorkingDays(startDate, days) {
  let count = 0;
  let current = new Date(startDate);
  // UK bank holidays 2025/2026 (approximate - in production, use a full list)
  const bankHolidays = [
    '2025-12-25', '2025-12-26', '2026-01-01', '2026-04-03', '2026-04-06',
    '2026-05-04', '2026-05-25', '2026-08-31', '2026-12-25', '2026-12-28'
  ];
  while (count < days) {
    current.setDate(current.getDate() + 1);
    const dayOfWeek = current.getDay();
    const dateStr = current.toISOString().split('T')[0];
    if (dayOfWeek !== 0 && dayOfWeek !== 6 && !bankHolidays.includes(dateStr)) {
      count++;
    }
  }
  return current;
}

const deadlineDate = addWorkingDays(receivedDate, 20);
const deadlineDateStr = deadlineDate.toLocaleDateString('en-GB', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

// Clean email body (remove excessive whitespace)
const rawBody = email.text || email.html || '';
const cleanBody = rawBody
  .replace(/<[^>]+>/g, '') // Strip HTML tags
  .replace(/\r\n/g, '\n')
  .replace(/\n{3,}/g, '\n\n')
  .trim()
  .substring(0, 3000); // Limit to 3000 chars for API

return [{
  json: {
    caseRef,
    senderEmail,
    senderName,
    subject: email.subject || '(No subject)',
    body: cleanBody,
    receivedDate: receivedDate.toISOString(),
    receivedDateStr,
    deadlineDate: deadlineDate.toISOString(),
    deadlineDateStr,
    rawFrom: from
  }
}];

// Build the Anthropic API payload for classification
const data = $input.item.json;

// System prompt — FOI agent summary (hardcoded for prompt caching)
const systemPrompt = `You are the Freedom of Information & EIR Agent for NHS Westshire Integrated Care Board (NHS Westshire ICB).

You process all FOI, EIR, SAR, and general information rights requests received at foi@westshire.icb.nhs.uk.

ICB QUICK FACTS:
- NHS Westshire ICB, Westshire House, 12 Cathedral Quarter, Westminster-upon-Avon WS1 2AB
- Population served: 521,000 | Annual budget: £1.12 billion | Staff: 387
- FOI Lead: Diane Okafor (Head of Corporate Affairs)
- DPO: Andrew Kellaway
- Established: 1 July 2022 (successor to 3 CCGs)

Your task is to classify the incoming request. Respond with a valid JSON object containing:
{
  "request_type": "FOI" | "EIR" | "SAR" | "GENERAL" | "UNCLEAR",
  "classification_confidence": "HIGH" | "MEDIUM" | "LOW",
  "summary": "[2-3 sentence summary of what is being requested]",
  "subject_matter": "[single phrase describing the topic, e.g. 'staff headcount', 'contract values', 'board minutes']",
  "potential_exemptions": ["list of potentially applicable FOIA exemptions, e.g. 's.40', 's.43'"],
  "escalation_required": true | false,
  "escalation_reason": "[reason for escalation if applicable, or null]",
  "requester_type": "MEMBER_OF_PUBLIC" | "JOURNALIST" | "MP" | "ACADEMIC" | "BUSINESS" | "UNKNOWN",
  "likely_held_by_icb": true | false | "UNCERTAIN",
  "initial_notes": "[any other relevant observations for the FOI Lead]"
}

IMPORTANT: Respond ONLY with the JSON object. No preamble, no explanation.`;

// User message with email content
const userMessage = `New request received at foi@westshire.icb.nhs.uk.

From: ${data.senderName} <${data.senderEmail}>
Subject: ${data.subject}
Date Received: ${data.receivedDateStr}
Case Reference Assigned: ${data.caseRef}

Email body:
---
${data.body}
---

Please classify this request.`;

return [{
  json: {
    ...data,
    apiPayload: {
      model: 'claude-sonnet-4-6',
      max_tokens: 1000,
      system: [
        {
          type: 'text',
          text: systemPrompt,
          cache_control: { type: 'ephemeral' }
        }
      ],
      messages: [
        {
          role: 'user',
          content: userMessage
        }
      ]
    }
  }
}];

// Parse the classification response from Claude
const response = $input.item.json;
const prevData = $('Code: Build API Payload').item.json;

// Extract text content from Anthropic response
let classificationText = '';
if (response.content && response.content[0] && response.content[0].text) {
  classificationText = response.content[0].text;
} else {
  throw new Error('Unexpected Anthropic API response structure: ' + JSON.stringify(response));
}

// Parse JSON from Claude's response
let classification;
try {
  // Claude should return pure JSON, but sometimes wraps in markdown code blocks
  const jsonMatch = classificationText.match(/```json\s*([\s\S]*?)\s*```/) ||
                    classificationText.match(/```\s*([\s\S]*?)\s*```/);
  const jsonStr = jsonMatch ? jsonMatch[1] : classificationText;
  classification = JSON.parse(jsonStr.trim());
} catch (e) {
  // Fallback if JSON parsing fails
  classification = {
    request_type: 'UNCLEAR',
    classification_confidence: 'LOW',
    summary: 'Unable to parse classification — manual review required.',
    subject_matter: 'unknown',
    potential_exemptions: [],
    escalation_required: true,
    escalation_reason: 'Classification parsing failed — manual review required.',
    requester_type: 'UNKNOWN',
    likely_held_by_icb: 'UNCERTAIN',
    initial_notes: `Raw Claude response: ${classificationText.substring(0, 500)}`
  };
}

// Log token usage for cost monitoring
const usage = response.usage || {};
console.log(`Token usage — Input: ${usage.input_tokens}, Output: ${usage.output_tokens}, Cache read: ${usage.cache_read_input_tokens || 0}`);

return [{
  json: {
    ...prevData,
    classification,
    claudeUsage: usage
  }
}];

// Build the disclosure analysis API payload
// This incorporates the knowledge base context and requests a full draft response
const data = $input.item.json;

// Knowledge base summary (in production, this would be loaded from the actual files)
const knowledgeBase = `## NHS WESTSHIRE ICB — KNOWLEDGE BASE SUMMARY

### Organisation
- NHS Westshire ICB, established 1 July 2022
- HQ: Westshire House, 12 Cathedral Quarter, Westminster-upon-Avon WS1 2AB
- Population: 521,000 | Budget: £1.12 billion | Staff: 387

### Key Personnel
- CEO: Sarah Thornton
- Chair: Dr James Whitmore
- CFO: Michael Chen
- Chief Nursing Officer: Dr Patricia Adeyemi
- Medical Director: Dr Robert Ashford
- CDIO: Helen Park
- DPO/IG Lead: Andrew Kellaway
- FOI Lead: Diane Okafor

### Provider Contracts
- Westshire University Hospitals NHS Trust: £580m (acute)
- Westshire Community Health NHS Trust: £142m (community)
- Westshire Mental Health Partnership: £98m (mental health)
- South West Ambulance: £24m (ICB share)
- Westshire Dental Network: £18m

### Workforce
- Total: 387 WTE | Sickness absence: 4.2% (national avg: 5.7%)
- CEO salary band: £135,000-£145,000
- Staff on AfC Bands 2-9 and VSM arrangements

### Property
- HQ (Westshire House): 5,200 sq ft, £180,000/year
- Chipping St Mary Satellite: 800 sq ft, £28,000/year

### Published Information (s.21 candidates)
- Annual Report and Accounts (ICB website)
- Board meeting minutes (ICB website, within 30 days)
- Gender Pay Gap Report (gov.uk)
- Staff Survey results (nhsstaffsurveys.com)
- Register of Declared Interests (ICB website)
- Integrated Care Strategy (ICB website)
- Contracts above £25,000 (Contracts Finder)
- Monthly spend data above £25,000 (ICB transparency pages)

### Complaints (2024/25)
- Total: 214 | Upheld/partial: 89 (42%) | Avg resolution: 23 days | PHSO refs: 7

### Primary Care Networks
- Westminster Central PCN: 38 GPs, 28,000 patients
- Westminster North & Brackley Vale PCN: 41 GPs, 34,000 patients
- Chipping St Mary PCN: 29 GPs, 22,000 patients
- Sutton Common Rural PCN: 24 GPs, 19,000 patients`;

const systemPrompt = `You are the Freedom of Information & EIR Agent for NHS Westshire ICB. You have already classified an incoming request. Now conduct a full disclosure analysis and draft the response.

${knowledgeBase}

## YOUR TASK

Analyse the FOI request and produce a structured JSON response containing:
{
  "disclosure_decision": "DISCLOSE" | "PARTIAL" | "REFUSE" | "NOT_HELD" | "REFER" | "TRANSFER" | "SAR_REDIRECT",
  "information_held": "[description of what information the ICB holds that is responsive]",
  "exemptions_applied": [
    {
      "section": "s.40",
      "description": "Personal data of third parties",
      "type": "ABSOLUTE" | "QUALIFIED",
      "public_interest_argument": "[PIT argument if qualified]"
    }
  ],
  "draft_acknowledgement": "[Full text of acknowledgement email to send to requester — include case reference, deadline, and ICB sign-off]",
  "draft_response": "[Full text of draft response for FOI Lead review — complete letter including disclosure or refusal notice as appropriate]",
  "internal_notes": "[Notes for FOI Lead — risks, sensitivities, recommended approach]",
  "s17_refusal_notice_required": true | false,
  "pit_required": true | false,
  "transfer_authority": "[name of authority to transfer to, if applicable]"
}

IMPORTANT: Respond ONLY with the JSON object.`;

const requestType = data.classification.request_type;
const legislation = requestType === 'EIR' ? 'Environmental Information Regulations 2004' : 'Freedom of Information Act 2000';

const userMessage = `Please conduct a full disclosure analysis for this ${requestType} request.

Case Reference: ${data.caseRef}
Date Received: ${data.receivedDateStr}
Deadline: ${data.deadlineDateStr}
From: ${data.senderName} <${data.senderEmail}>
Subject: ${data.subject}
Classification: ${JSON.stringify(data.classification, null, 2)}

Request body:
---
${data.body}
---

Applicable legislation: ${legislation}
Prepare the draft acknowledgement and draft response.`;

return [{
  json: {
    ...data,
    analysisPayload: {
      model: 'claude-sonnet-4-6',
      max_tokens: 4000,
      system: [
        {
          type: 'text',
          text: systemPrompt,
          cache_control: { type: 'ephemeral' }
        }
      ],
      messages: [
        {
          role: 'user',
          content: userMessage
        }
      ]
    }
  }
}];

// Parse the full disclosure analysis response from Claude
const response = $input.item.json;
const prevData = $('Code: Build Disclosure Analysis Payload').item.json;

let analysisText = '';
if (response.content && response.content[0] && response.content[0].text) {
  analysisText = response.content[0].text;
} else {
  throw new Error('Unexpected Anthropic API response: ' + JSON.stringify(response));
}

// Parse JSON
let analysis;
try {
  const jsonMatch = analysisText.match(/```json\s*([\s\S]*?)\s*```/) ||
                    analysisText.match(/```\s*([\s\S]*?)\s*```/);
  const jsonStr = jsonMatch ? jsonMatch[1] : analysisText;
  analysis = JSON.parse(jsonStr.trim());
} catch (e) {
  analysis = {
    disclosure_decision: 'UNCLEAR',
    information_held: 'Unable to determine — manual review required.',
    exemptions_applied: [],
    draft_acknowledgement: `Dear ${prevData.senderName},\n\nThank you for your request received on ${prevData.receivedDateStr}. This has been logged as case ${prevData.caseRef}. We will respond within 20 working days.\n\nFreedom of Information Team\nNHS Westshire ICB`,
    draft_response: 'MANUAL REVIEW REQUIRED — automated analysis failed.',
    internal_notes: `Analysis parsing failed. Raw response: ${analysisText.substring(0, 1000)}`,
    s17_refusal_notice_required: false,
    pit_required: false,
    transfer_authority: null
  };
}

const usage = response.usage || {};
console.log(`Analysis token usage — Input: ${usage.input_tokens}, Output: ${usage.output_tokens}`);

return [{
  json: {
    ...prevData,
    analysis,
    analysisUsage: usage
  }
}];

