// Prepare the log entry for Google Sheets
const data = $input.item.json;

const now = new Date();
const loggedAt = now.toLocaleDateString('en-GB') + ' ' + now.toLocaleTimeString('en-GB', {hour: '2-digit', minute: '2-digit'});

return [{
  json: {
    logEntry: [
      data.caseRef,
      data.receivedDateStr,
      data.senderName,
      data.senderEmail,
      data.subject,
      data.classification.request_type,
      data.classification.subject_matter,
      data.deadlineDateStr,
      data.analysis.disclosure_decision,
      data.classification.potential_exemptions.join('; ') || 'None',
      data.classification.escalation_required ? 'YES' : 'NO',
      data.classification.escalation_reason || '',
      'PENDING_REVIEW',
      loggedAt,
      data.analysis.draft_acknowledgement.substring(0, 200) + '...'
    ],
    ...data
  }
}];
